Code.Terraform:
```hcl
# Terraform: 启用 Athena 工作组查询结果的加密
resource "aws_athena_workgroup" "<example_resource_name>" {
  name = "<example_resource_name>"

  configuration {
    result_configuration {
      output_location = "s3://<example_bucket>/"  # 查询结果所需的 S3 路径
      encryption_configuration {
        encryption_option = "SSE_S3"  # 关键：为查询结果启用加密
      }
    }
  }
}
```
